Class ItemProcessor Extends %RegisteredObject
{
    /// Remove items marked for deletion and return remaining count
    ClassMethod ProcessItems(items As %ListOfDataTypes) As %Integer
    {
        // BUGGY: Modifying list while iterating causes skipped items
        For i=1:1:items.Count() {
            Set item = items.GetAt(i)
            If (item [ "DELETE") {
                Do items.RemoveAt(i)
            }
        }
        Quit items.Count()
    }
}

