Class TestItemProcessor Extends %RegisteredObject
{
    ClassMethod TestProcessItems()
    {
        Set items = ##class(%ListOfDataTypes).%New()
        Do items.Insert("keep1")
        Do items.Insert("DELETE_this")
        Do items.Insert("DELETE_that")
        Do items.Insert("keep2")
        Do items.Insert("DELETE_also")

        Set remaining = ##class(ItemProcessor).ProcessItems(items)

        // Should have 2 items remaining (keep1, keep2)
        If (remaining '= 2) {
            Throw ##class(%Exception.General).%New("Should have 2 items, got "_remaining)
        }

        // Verify no DELETE items remain
        For i=1:1:items.Count() {
            If (items.GetAt(i) [ "DELETE") {
                Throw ##class(%Exception.General).%New("DELETE item still present: "_items.GetAt(i))
            }
        }
    }
}
